contracts/LandRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract LandRegistry {
  enum Status { Pending, Approved, Rejected }

  struct Parcel {
    uint256 id;
    string titleNumber;
    string location;
    string ipfsHash;
    address owner;
    Status status;
  }

  uint256 public parcelCount;
  mapping(uint256 => Parcel) public parcels;
  mapping(string => bool) public titleExists;

  address public officer;

  event ParcelSubmitted(uint256 indexed parcelId, address indexed owner, string titleNumber);
  event ParcelApproved(uint256 indexed parcelId, address indexed officer);
  event ParcelRejected(uint256 indexed parcelId, address indexed officer);

  modifier onlyOfficer() {
    require(msg.sender == officer, "Not authorized");
    _;
  }

  constructor() {
    officer = msg.sender;
  }

  function submitParcel(
    string memory _titleNumber,
    string memory _location,
    string memory _ipfsHash
  ) external returns (uint256) {
    require(!titleExists[_titleNumber], "Title already exists");
    parcelCount++;
    parcels[parcelCount] = Parcel(
      parcelCount,
      _titleNumber,
      _location,
      _ipfsHash,
      msg.sender,
      Status.Pending
    );
    titleExists[_titleNumber] = true;
    emit ParcelSubmitted(parcelCount, msg.sender, _titleNumber);
    return parcelCount;
  }

  function approveParcel(uint256 _parcelId) external onlyOfficer {
    require(parcels[_parcelId].id != 0, "Parcel not found");
    require(parcels[_parcelId].status == Status.Pending, "Not pending");
    parcels[_parcelId].status = Status.Approved;
    emit ParcelApproved(_parcelId, msg.sender);
  }

  function rejectParcel(uint256 _parcelId) external onlyOfficer {
    require(parcels[_parcelId].id != 0, "Parcel not found");
    require(parcels[_parcelId].status == Status.Pending, "Not pending");
    parcels[_parcelId].status = Status.Rejected;
    emit ParcelRejected(_parcelId, msg.sender);
  }

  function getParcel(uint256 _parcelId) external view returns (Parcel memory) {
    return parcels[_parcelId];
  }
}

contracts/Ownership.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract Ownership {
  struct Transfer {
    uint256 parcelId;
    address from;
    address to;
    uint256 timestamp;
    bool confirmed;
  }

  mapping(uint256 => address) public currentOwner;
  mapping(uint256 => Transfer) public pendingTransfer;
  mapping(uint256 => Transfer[]) public transferHistory;

  event TransferInitiated(uint256 indexed parcelId, address indexed from, address indexed to);
  event TransferConfirmed(uint256 indexed parcelId, address indexed from, address indexed to);

  function setInitialOwner(uint256 _parcelId, address _owner) external {
    require(currentOwner[_parcelId] == address(0), "Owner already set");
    currentOwner[_parcelId] = _owner;
  }

  function initiateTransfer(uint256 _parcelId, address _buyer) external {
    require(currentOwner[_parcelId] == msg.sender, "Not the owner");
    require(_buyer != address(0), "Invalid buyer");
    pendingTransfer[_parcelId] = Transfer(
      _parcelId,
      msg.sender,
      _buyer,
      block.timestamp,
      false
    );
    emit TransferInitiated(_parcelId, msg.sender, _buyer);
  }

  function confirmTransfer(uint256 _parcelId) external {
    Transfer storage t = pendingTransfer[_parcelId];
    require(t.to == msg.sender, "Not the buyer");
    require(!t.confirmed, "Already confirmed");
    t.confirmed = true;
    currentOwner[_parcelId] = msg.sender;
    transferHistory[_parcelId].push(t);
    delete pendingTransfer[_parcelId];
    emit TransferConfirmed(_parcelId, t.from, msg.sender);
  }

  function getHistory(uint256 _parcelId) external view returns (Transfer[] memory) {
    return transferHistory[_parcelId];
  }
}

contracts/Verification.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./Ownership.sol";
import "./LandRegistry.sol";

contract Verification {
  LandRegistry public registry;
  Ownership public ownership;

  constructor(address _registry, address _ownership) {
    registry = LandRegistry(_registry);
    ownership = Ownership(_ownership);
  }

  function verifyOwner(uint256 _parcelId) external view returns (address) {
    return ownership.currentOwner(_parcelId);
  }

  function getParcelDetails(uint256 _parcelId) external view returns (
    LandRegistry.Parcel memory parcel,
    address owner
  ) {
    parcel = registry.getParcel(_parcelId);
    owner = ownership.currentOwner(_parcelId);
  }

  function getTransferHistory(uint256 _parcelId) external view returns (
    Ownership.Transfer[] memory
  ) {
    return ownership.getHistory(_parcelId);
  }
}

